     1→import React, { FC, useEffect, useState, useLayoutEffect, useMemo, useRef } from 'react';
     2→import { NavigationProp, useNavigation, useIsFocused, useFocusEffect } from '@react-navigation/native';
     3→import { Dimensions } from 'react-native';
     4→import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
     5→
     6→import { useScreenViewTracking } from '../../hooks/tracking';
     7→import { usePermission, usePoints, useRescue } from '../../services';
     8→import type { RescuePayload } from '../../services';
     9→
    10→import theme from '../../styles/theme';
    11→import { InvoiceCashbackProps } from './models';
    12→import { PropsRootStack } from '../../routes/Models';
    13→import InvoiceCashbackSummaryView from './view';
    14→
    15→const InvoiceCashbackSummary: FC<InvoiceCashbackProps> = ({ route }) => {
    16→  useScreenViewTracking({ route, title: 'Cashback na fatura' });
    17→  const navigation = useNavigation<NavigationProp<PropsRootStack>>();
    18→  const isFocused = useIsFocused();
    19→  const { height } = Dimensions.get('window');
    20→  const { hasRedeemed, markAsRedeemed } = usePermission();
    21→  const alreadyMarkedRef = useRef(false);
    22→  const [hasAttemptedRescue, setHasAttemptedRescue] = useState(false);
    23→
    24→  const { conversionFactor } = usePoints();
    25→  const {
    26→    isLoading: isRescueLoading,
    27→    isError: isRescueFailed,
    28→    responseStatus: rescueStatus,
    29→    rescueRequest,
    30→    reset: rescueClear,
    31→  } = useRescue();
    32→
    33→  useLayoutEffect(() => {
    34→    if (isFocused) {
    35→      setHasAttemptedRescue(false);
    36→      rescueClear();
    37→    }
    38→  }, [isFocused, rescueClear]);
    39→
    40→  useFocusEffect(
    41→    React.useCallback(() => {
    42→      setHasAttemptedRescue(false);
    43→      rescueClear();
    44→      return undefined;
    45→    }, [rescueClear])
    46→  );
    47→
    48→  const handleGoBack = () => {
    49→    setHasAttemptedRescue(false);
    50→    rescueClear();
    51→    navigation.goBack();
    52→  };
    53→
    54→  const invoiceList = (pts: number): any[] => {
    55→    const whiteShape = theme.colors.LIGHT_BASE_01;
    56→    const fintechColor = theme.colors.SECONDARY_COLOR_02;
    57→    const finalPrice = pts * conversionFactor;
    58→    const formattedPrice = new Intl.NumberFormat('pt-BR', {
    59→      style: 'currency',
    60→      currency: 'BRL',
    61→    }).format(finalPrice);
    62→
    63→    return [
    64→      {
    65→        type: 'default',
    66→        icon: 'icon-switch-vertical',
    67→        iconColor: fintechColor,
    68→        iconColorShape: whiteShape,
    69→        description: `Cada ${pts.toLocaleString(
    70→          'pt-br'
    71→        )} pontos valem ${formattedPrice} no cashback`,
    72→      },
    73→      {
    74→        type: 'default',
    75→        icon: 'icon-calendar',
    76→        iconColor: fintechColor,
    77→        iconColorShape: whiteShape,
    78→        description: 'Você define quanto cashback quer aplicar na sua fatura aberta',
    79→      },
    80→      {
    81→        type: 'default',
    82→        icon: 'icon-payment-invoice',
    83→        iconColor: fintechColor,
    84→        iconColorShape: whiteShape,
    85→        description: 'Se o valor for maior que o da fatura, a diferença será aplicada nas próximas',
    86→      },
    87→      {
    88→        type: 'default',
    89→        icon: 'icon-clock',
    90→        iconColor: fintechColor,
    91→        iconColorShape: whiteShape,
    92→        description: 'O cashback acontece em até 72h',
    93→      },
    94→    ];
    95→  };
    96→
    97→  const pointsSelected = route?.params?.pointsSelected ?? 0;
    98→  const reaisSelected = route?.params?.reaisSelected ?? 0;
    99→  const productCode = route?.params?.productCode;
   100→  const campaingId = route?.params?.campaingId;
   101→
   102→  const onConfirmRescue = () => {
   103→    setHasAttemptedRescue(true);
   104→    const payload: RescuePayload = {
   105→      value: pointsSelected,
   106→      campaignId: campaingId,
   107→      productCode: productCode,
   108→      description: 'Cashback resgatado',
   109→    };
   110→    rescueRequest(payload);
   111→  };
   112→
   113→  const onExitResult = () => {
   114→    setHasAttemptedRescue(false);
   115→    rescueClear();
   116→    navigation.navigate('RewardProgram');
   117→  };
   118→
   119→  const isRescueConcluded = !isRescueFailed && !!rescueStatus;
   120→  const showResult = isFocused && hasAttemptedRescue && (isRescueConcluded || isRescueFailed);
   121→
   122→  const items = invoiceList(pointsSelected).map((item) => ({
   123→    icon: item.icon,
   124→    iconColor: item.iconColor,
   125→    description: item.description,
   126→    iconColorShape: item.iconColorShape,
   127→    type: item.type,
   128→  }));
   129→
   130→  const modalizeRef1 = useRef<PropsModalizeRef>(null as unknown as PropsModalizeRef);
   131→
   132→  const onOpenDefault = () => {
   133→    modalizeRef1.current?.open?.();
   134→  };
   135→
   136→  useEffect(() => {
   137→    if (showResult && isRescueConcluded && !alreadyMarkedRef.current && hasRedeemed !== true) {
   138→      alreadyMarkedRef.current = true;
   139→      markAsRedeemed().catch(() => {});
   140→    }
   141→  }, [showResult, isRescueConcluded, hasRedeemed, markAsRedeemed]);
   142→
   143→  const nfPtBR = useMemo(() => new Intl.NumberFormat('pt-BR'), []);
   144→  const getFormatPoints = (n: number) => nfPtBR.format(Math.max(0, Math.floor(n || 0)));
   145→  const formatCurrencyBR = (n: number) =>
   146→    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' })
   147→      .format(Number.isFinite(n) ? n : 0)
   148→      .replace(/\s/g, '');
   149→
   150→  const formattedSelectedPoints = useMemo(
   151→    () => getFormatPoints(pointsSelected || 0),
   152→    [pointsSelected]
   153→  );
   154→
   155→  const formattedSelectedReais = useMemo(
   156→    () => formatCurrencyBR(reaisSelected || 0),
   157→    [reaisSelected]
   158→  );
   159→
   160→  const effectiveShowResult =
   161→    typeof showResult !== 'undefined' ? showResult : !!(isRescueConcluded || isRescueFailed);
   162→  const screenTitle = effectiveShowResult ? 'Conclusão' : 'Cashback na fatura';
   163→
   164→  return (
   165→    <InvoiceCashbackSummaryView
   166→      handleGoBack={handleGoBack}
   167→      onConfirmRescue={onConfirmRescue}
   168→      onExitResult={onExitResult}
   169→      isRescueLoading={isRescueLoading}
   170→      isRescueConcluded={isRescueConcluded}
